import{_ as a,o,c as r,ae as s}from"./chunks/framework.BvHJbMD4.js";const u=JSON.parse('{"title":"Herramientas Requeridas","description":"","frontmatter":{},"headers":[],"relativePath":"tools.md","filePath":"tools.md"}'),t={name:"tools.md"};function n(i,e,l,d,c,m){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="herramientas-requeridas" tabindex="-1">Herramientas Requeridas <a class="header-anchor" href="#herramientas-requeridas" aria-label="Permalink to &quot;Herramientas Requeridas&quot;">​</a></h1><p>Para desarrollar y ejecutar el proyecto <strong>Structo</strong>, es necesario instalar las siguientes herramientas en tu entorno de desarrollo.</p><p>El proyecto está compuesto por un backend en .NET y un frontend en Nuxt.js, e interactúa con bases de datos SQL Server y MongoDB.</p><h2 id="herramientas-base-requeridas" tabindex="-1">Herramientas Base (Requeridas) <a class="header-anchor" href="#herramientas-base-requeridas" aria-label="Permalink to &quot;Herramientas Base (Requeridas)&quot;">​</a></h2><h3 id="_1-node-js-npm" tabindex="-1">1. Node.js &amp; npm <a class="header-anchor" href="#_1-node-js-npm" aria-label="Permalink to &quot;1. Node.js &amp; npm&quot;">​</a></h3><p>Requerido para el frontend (Nuxt) y para la documentación (VitePress).</p><ul><li><strong>Propósito</strong>: Ejecutar el servidor de desarrollo de Nuxt, compilar el frontend, y gestionar las dependencias del ecosistema JavaScript.</li><li><strong>Instalación</strong>: Se recomienda instalar la versión LTS actual. Puedes descargarlo desde <a href="https://nodejs.org/" target="_blank" rel="noreferrer">nodejs.org</a> o usar un gestor de versiones como <code>nvm</code>.</li></ul><h3 id="_2-net-sdk" tabindex="-1">2. .NET SDK <a class="header-anchor" href="#_2-net-sdk" aria-label="Permalink to &quot;2. .NET SDK&quot;">​</a></h3><p>Requerido para el backend escrito en C#.</p><ul><li><strong>Propósito</strong>: Compilar y ejecutar la solución <code>Structo.sln</code> y los diversos proyectos ubicados en la carpeta <code>backend/</code>.</li><li><strong>Instalación</strong>: Descarga e instala el .NET SDK desde la <a href="https://dotnet.microsoft.com/download" target="_blank" rel="noreferrer">página oficial de Microsoft</a>. Verifica la versión específica requerida por los proyectos examinando <code>Directory.Build.props</code> o los archivos <code>.csproj</code>.</li></ul><h3 id="_3-sql-server" tabindex="-1">3. SQL Server <a class="header-anchor" href="#_3-sql-server" aria-label="Permalink to &quot;3. SQL Server&quot;">​</a></h3><p>Requerido como base de datos relacional del sistema.</p><ul><li><strong>Propósito</strong>: Almacenar la información principal de la plataforma.</li><li><strong>Instalación</strong>: Puedes instalar <a href="https://www.microsoft.com/es-es/sql-server/sql-server-downloads" target="_blank" rel="noreferrer">SQL Server Developer Edition</a> de forma local.</li></ul><h3 id="_4-mongodb" tabindex="-1">4. MongoDB <a class="header-anchor" href="#_4-mongodb" aria-label="Permalink to &quot;4. MongoDB&quot;">​</a></h3><p>Requerido como base de datos NoSQL del sistema.</p><ul><li><strong>Propósito</strong>: Almacenar documentos y datos no relacionales de la plataforma.</li><li><strong>Instalación</strong>: Descarga e instala <a href="https://www.mongodb.com/try/download/community" target="_blank" rel="noreferrer">MongoDB Community Server</a>.</li></ul><h3 id="_5-git" tabindex="-1">5. Git <a class="header-anchor" href="#_5-git" aria-label="Permalink to &quot;5. Git&quot;">​</a></h3><p>Requerido para el control de versiones.</p><ul><li><strong>Propósito</strong>: Clonar el repositorio y gestionar los cambios en el código.</li><li><strong>Instalación</strong>: Disponible en <a href="https://git-scm.com/" target="_blank" rel="noreferrer">git-scm.com</a>.</li></ul><hr><h2 id="herramientas-opcionales-recomendadas" tabindex="-1">Herramientas Opcionales / Recomendadas <a class="header-anchor" href="#herramientas-opcionales-recomendadas" aria-label="Permalink to &quot;Herramientas Opcionales / Recomendadas&quot;">​</a></h2><h3 id="docker-y-docker-compose-opcional" tabindex="-1">Docker y Docker Compose (Opcional) <a class="header-anchor" href="#docker-y-docker-compose-opcional" aria-label="Permalink to &quot;Docker y Docker Compose (Opcional)&quot;">​</a></h3><p>Si prefieres no instalar los servicios (como las bases de datos) directamente en tu equipo local, puedes levantarlos utilizando contenedores.</p><ul><li><strong>Propósito</strong>: Levantar las dependencias de infraestructura localmente de manera aislada.</li><li><strong>Instalación</strong>: Instala <a href="https://www.docker.com/products/docker-desktop/" target="_blank" rel="noreferrer">Docker Desktop</a> (Windows/Mac) o Docker Engine (Linux). Asegúrate de que <code>docker-compose</code> esté disponible.</li></ul><h3 id="dbeaver-recomendado" tabindex="-1">DBeaver (Recomendado) <a class="header-anchor" href="#dbeaver-recomendado" aria-label="Permalink to &quot;DBeaver (Recomendado)&quot;">​</a></h3><ul><li><strong>Propósito</strong>: Cliente visual universal para la gestión de bases de datos relacionales, muy útil para interactuar con SQL Server.</li><li><strong>Instalación</strong>: Disponible de forma gratuita en <a href="https://dbeaver.io/" target="_blank" rel="noreferrer">dbeaver.io</a>.</li></ul><p><em>(Alternativas: SQL Server Management Studio (SSMS) o Azure Data Studio).</em></p><h3 id="mongodb-compass-recomendado" tabindex="-1">MongoDB Compass (Recomendado) <a class="header-anchor" href="#mongodb-compass-recomendado" aria-label="Permalink to &quot;MongoDB Compass (Recomendado)&quot;">​</a></h3><ul><li><strong>Propósito</strong>: Interfaz gráfica oficial para explorar e interactuar con tus colecciones y bases de datos en MongoDB.</li><li><strong>Instalación</strong>: Puedes descargarlo desde <a href="https://www.mongodb.com/products/tools/compass" target="_blank" rel="noreferrer">mongodb.com/products/tools/compass</a>.</li></ul>',29)])])}const h=a(t,[["render",n]]);export{u as __pageData,h as default};
